{
  id: "albatrellus-ovinus",
  commonNames: ["Sheep Polypore", "Sheep's Foot", "Forest Lamb", "Sheep Mushroom"],
  scientific: "Albatrellus ovinus",
  family: "Albatrellaceae",
  order: "Russulales",
  trophicMode: "mycorrhizal",
  mycorrhizalPartners: ["Picea (spruce)", "possibly other conifers"],
  hostTrees: [
    { common: "Engelmann spruce", scientific: "Picea engelmannii" },
    { common: "Sitka spruce", scientific: "Picea sitchensis" },
    { common: "White spruce", scientific: "Picea glauca" }
  ],
  substrate: "Terrestrial; on moss-covered duff and soil in conifer (especially spruce) forests; unusual among polypores in being mycorrhizal and ground-dwelling rather than wood-decaying.",
  habitat: "Mature montane and subalpine spruce forests, often in mossy ground with deep duff; frequently fruits in dense clusters or troops, sometimes with caps fused together.",
  elevationM: { min: 600, max: 2200 },
  regionsPNW: [
    "Cascades (WA, OR)",
    "Olympic Peninsula",
    "Coastal BC",
    "Interior BC",
    "Northern Rockies (ID, MT)",
    "Blue Mountains (OR/WA)"
  ],
  fruitingMonths: [7, 8, 9, 10, 11],
  peakMonths: [9, 10],
  conditions: {
    minRain7d: 25,
    idealDaysSinceRain: [4, 10],
    tempRangeC: [5, 18],
    humidityMinPct: 70
  },
  identification: {
    cap: "7-18 cm across, irregular and often distorted or lobed, creamy white to pale grey or buff-brown, convex then flattening with a central depression; surface dry, smooth becoming cracked with age or in dry weather; margin wavy, incurved; multiple caps frequently fuse together.",
    underside: "Small white to creamy yellow decurrent pores (2-4 per mm), oval, staining lemon to greenish-yellow when bruised or cut; tubes short (1-4 mm).",
    stem: "Central or off-center, 3-7 cm tall, 1-3 cm thick, whitish to pale tan, smooth or finely velvety, often short and stout.",
    fleshColor: "White, firm and brittle; stains/discolors yellow to lemon-yellow (sometimes greenish-yellow) when cut or bruised, especially in the tubes and near the cuticle.",
    sporePrintColor: "White",
    odor: "Mild, sometimes faintly fruity or pleasant; not distinctive; taste mild to slightly bitter when raw.",
    sizeCm: "Cap 7-18 cm; stem 3-7 x 1-3 cm"
  },
  edibility: "edible-when-cooked",
  toxicityNotes: "Bitter and unpalatable when raw; bitterness largely diminishes with cooking. No significant toxicity reported, but easily confused with the bitter, inedible Albatrellus confluens / Albatrellopsis confluens; misidentification can lead to disappointing or GI-upsetting meals. North American collections historically called 'A. ovinus' may represent A. avellaneus, A. confluens, or sister species - molecular work suggests true A. ovinus sensu stricto is largely European/Eurasian and Picea-restricted; verify with local experts.",
  lookalikes: [
    { name: "Pink-tinged Polypore (Forager's Polypore)", scientific: "Albatrellopsis confluens (=Albatrellus confluens)", catalogId: "albatrellopsis-confluens", danger: "inedible", keyFeatures: ["pinkish-tan to apricot cap","bitter even cooked","fused clusters"], distinguishingFeature: "Pinkish-tan to apricot or salmon cap, flesh distinctly bitter even after cooking, less pronounced yellow staining; often grows in fused clusters and overlaps in habitat." },
    { name: "Western Albatrellus", scientific: "Albatrellus subrubescens", catalogId: "albatrellus-subrubescens", danger: "toxic", keyFeatures: ["violet/pinkish cap tinge","bruises orange","amyloid spores","under pines"], distinguishingFeature: "Cap often with violet or pinkish tinge, bruises orange; spores amyloid (vs. inamyloid in A. ovinus); usually under pines." },
    { name: "Blue-capped Polypore", scientific: "Albatrellus flettii (=Albatrellopsis flettii)", catalogId: "albatrellus-flettii", danger: "edible", keyFeatures: ["blue to blue-green cap","fading to buff","PNW conifers"], distinguishingFeature: "Distinct blue to blue-green cap when young, fading to buff; common PNW species under conifers." },
    { name: "Wood Hedgehog", scientific: "Hydnum repandum", catalogId: "hydnum-repandum", danger: "edible", keyFeatures: ["soft white teeth/spines","tan-orange cap","no yellow staining"], distinguishingFeature: "Underside with soft white teeth/spines rather than pores; cap typically tan-orange, never stains yellow." },
    { name: "Lemon-yellow Albatrellus", scientific: "Albatrellus citrinus", catalogId: "albatrellus-citrinus", danger: "inedible", keyFeatures: ["strongly yellow overall","Picea-associated"], distinguishingFeature: "More strongly yellow-pigmented overall, also Picea-associated; recently segregated from A. ovinus in Europe by molecular data." }
  ],
  culinary: {
    flavor: "Mild, nutty and pleasantly mushroomy when cooked; bright yellow color develops on sauteing; can carry a faint bitterness depending on age and collection - young specimens are best.",
    preparation: "Always cook thoroughly; bitter raw. Slice thinly and saute in butter (often after a brief parboil to reduce any residual bitterness). Holds shape well; good in soups, stews, sauces, and alongside game. Discard tough stem bases.",
    preservation: "Dries well when sliced thin; can also be sauteed and frozen. Pickling is used in parts of Europe (notably Scandinavia)."
  },
  conservationNotes: "Not formally threatened across its Holarctic range, but locally tied to mature/old-growth spruce forests; populations sensitive to clear-cutting and loss of mossy duff layer. North American taxonomy unresolved - field guides increasingly note that 'A. ovinus' in NA may represent multiple species (A. avellaneus, A. confluens s.l., or undescribed sister taxa), so collections contribute to ongoing molecular study.",
  sources: [
    { name: "First Nature - Albatrellus ovinus (Forest Lamb / Sheep Polypore)", url: "https://www.first-nature.com/fungi/albatrellus-ovinus.php" },
    { name: "Mushroom World - Albatrellus ovinus", url: "https://www.mushroom.world/show?n=Albatrellus-ovinus" },
    { name: "Wu et al. 2024 - Diversity, divergence time, and biogeography of the genus Albatrellus (Mycology)", url: "https://www.tandfonline.com/doi/full/10.1080/21501203.2024.2386021" },
    { name: "NCBI Taxonomy - Albatrellus ovinus", url: "https://www.ncbi.nlm.nih.gov/Taxonomy/Browser/wwwtax.cgi?id=139090" },
    { name: "Wild Food Girl - Albatrellus confluens / ovinus discussion", url: "https://wildfoodgirl.com/2011/albatrellus-confluens-conference" },
    { name: "Wikipedia - Albatrellus subrubescens (taxonomy of Albatrellus clade)", url: "https://en.wikipedia.org/wiki/Albatrellus_subrubescens" }
  ],
  spores: { lengthMicrons: [4, 5], widthMicrons: [2.5, 3.5], shape: "ellipsoidal to subglobose", ornamentation: "smooth, thin- to slightly thick-walled, with a germ pore", reaction: "inamyloid (does not stain in Melzer's reagent) - key distinction from amyloid, warty-spored A. subrubescens", notes: "Gloeoplerous hyphae present (stain in phloxine); clamp connections absent; KOH on flesh produces dirty golden yellow reaction. Spore inamyloidy is the most reliable single character separating A. ovinus from sister species." },
  microhabitat: { slopeAspect: "Often occupies entire shaded, cool montane slopes; no strong aspect preference but favors damp, north- or east-facing or otherwise shaded positions in southern parts of range", soilPh: [4.5, 6.0], soilTexture: "Deep organic duff over coarse, well-drained mineral soils; thick moss layer typical", moisturePreference: "Consistently moist but not waterlogged; thrives in cool, humid pockets with retained duff moisture", indicatorPlants: ["Picea spp. (spruce)", "feather mosses (Hylocomium splendens, Pleurozium schreberi)", "Vaccinium spp. (huckleberry/blueberry)", "subalpine fir (Abies lasiocarpa) in mixed stands"], notes: "Generally acidophilic on conifer duff; contrast with the segregated A. citrinus, which is reported from lime-rich (calcareous, higher pH) Picea abies soils in Scandinavia (Ryman et al. 2003)." },
  phenologyCues: [
    { cue: "Sustained late-summer rains (>=25 mm over 7 days) following a cool, humid spell", reliability: "strong" },
    { cue: "Night temperatures dropping consistently into 5-10 C range in montane spruce zones", reliability: "strong" },
    { cue: "Fruiting often follows 4-10 days after a soaking rain, with mossy duff still visibly damp", reliability: "moderate" },
    { cue: "Co-fruiting with other ectomycorrhizal spruce associates (e.g., Russula, Lactarius, Hydnum spp.)", reliability: "moderate" },
    { cue: "Local lore of fruiting in the same troops/rings year after year once a colony is established", reliability: "anecdotal" }
  ],
  bioactive: { compounds: ["grifolin", "neogrifolin", "scutigeral", "confluentin (trace)", "neogrifolin-derived antioxidant phenols (Nukata et al. 2002)", "flavonoids (Wei & Li 2016)"], medicinalUses: ["TRPV1 receptor antagonism - basis for cosmetic anti-redness / sensitive-skin formulations (Hettwer et al. 2017, IJCS)", "antioxidant activity (neogrifolin derivatives, Phytochemistry 2002)", "scutigeral reported to modulate dopamine receptors and dampen pain signalling (preliminary)"], toxinsOfNote: [], notes: "No notable mammalian toxins; bioactivity is dominated by prenylated phenols (grifolin family) shared with A. confluens. Bitter principle in raw flesh is largely these same prenylated phenols, which degrade or extract out on cooking." },
  dnaBarcode: { itsClade: "Russuloid Albatrellus s.s. clade (Albatrellaceae); ITS analyses place A. ovinus, A. citrinus, and A. subrubescens as closely related Picea/conifer-associated sister taxa, with A. confluens / Albatrellopsis confluens in a separate, polyporoid-affiliated clade", keyPaper: "Ryman, Fransson, Johannesson & Danell 2003 - 'Albatrellus citrinus sp. nov., connected to Picea abies on lime rich soils', Mycological Research 107(10):1243-1246; see also Wu et al. 2024, Mycology, on Albatrellus divergence and biogeography", notes: "ITS barcoding has driven recent splits (A. citrinus segregated from A. ovinus; A. confluens moved to Albatrellopsis). North American 'A. ovinus' material is undersampled and may include A. avellaneus and undescribed sister species - confirm via ITS rather than morphology alone." },
  verification: { sourcesAgreeing: 6, lastVerified: "2026-05-23", consensus: "strong", disputeNotes: "Macroscopic ID and ecology are strongly agreed across sources. Disputes are taxonomic: (1) the species concept of A. ovinus in North America is unresolved and likely paraphyletic relative to A. avellaneus / A. confluens s.l.; (2) the segregate A. citrinus (calcicolous, lime-rich Picea soils) is accepted in Europe but rarely applied in NA keys; (3) some older sources still list 'Polyporaceae' as family - current placement is Albatrellaceae in Russulales." }
}
