    fleshColor: "White throughout, sometimes pale yellow just beneath the cap cuticle; unchanging when sliced.",
    sporePrintColor: "White",
    odor: "Mild, not distinctive; faintly earthy.",
    sizeCm: "Cap 6-39 cm (commonly 8-20); stem 7-18 x 2-3.5 cm"
