{
  id: "auricularia-americana",
  commonNames: ["American wood ear", "Wood ear", "Tree ear", "Jelly ear", "Conifer wood ear"],
  scientific: "Auricularia americana",
  family: "Auriculariaceae",
  order: "Auriculariales",
  trophicMode: "saprotrophic",
  mycorrhizalPartners: null,
  hostTrees: [
    { common: "Western hemlock", scientific: "Tsuga heterophylla" },
    { common: "Mountain hemlock", scientific: "Tsuga mertensiana" },
    { common: "Sitka spruce", scientific: "Picea sitchensis" },
    { common: "Engelmann spruce", scientific: "Picea engelmannii" },
    { common: "Subalpine fir", scientific: "Abies lasiocarpa" },
    { common: "Pacific silver fir", scientific: "Abies amabilis" },
    { common: "Grand fir", scientific: "Abies grandis" },
    { common: "Douglas-fir", scientific: "Pseudotsuga menziesii" },
    { common: "Lodgepole pine", scientific: "Pinus contorta" }
  ],
  substrate: "Dead, dying, or recently fallen coniferous wood: logs, large branches, snags, and stumps with bark still intact and early-stage decay. A white-rot wood-decay saprotroph; the strict-sense A. americana (Looney et al. 2013; Wu et al. 2015) is the only North American Auricularia restricted to conifer substrates and is microscopically distinguished by the absence of a medullary zone in cross-section.",
  habitat: "Solitary, clustered, or in shelving rows on the underside and sides of fallen conifer logs and standing snags in shaded, humid old-growth and mature mixed-conifer forests. Most abundant in coastal hemlock-spruce rainforest and montane spruce-fir stands following soaking rains. Fruit bodies are remarkably desiccation-tolerant: they shrivel to hard, dark, cartilaginous flakes in dry weather and rehydrate within hours of rain, resuming spore production from the same basidiocarp across multiple wet/dry cycles over weeks.",
  elevationM: { min: 0, max: 2200 },
  regionsPNW: ["Coastal British Columbia", "Vancouver Island", "Olympic Peninsula", "Western Washington Cascades", "Western Oregon Cascades", "Oregon Coast Range", "Puget Sound lowlands", "Columbia River Gorge", "Northern Idaho panhandle", "Inland Northwest montane forests"],
  fruitingMonths: [3, 4, 5, 6, 7, 8, 9, 10, 11],
  peakMonths: [4, 5, 10, 11],
  conditions: {
    minRain7d: 10,
    idealDaysSinceRain: [0, 5],
    tempRangeC: [2, 22],
    humidityMinPct: 75
  },
  identification: {
    cap: "Ear-, disc-, or cup-shaped when young, becoming irregular, lobed, wavy, or floppy with age; 2-10 cm across; upper (sterile) surface brown to reddish-brown or purplish-brown, finely tomentose with short pale hairs, often appearing minutely velvety; surface often frosted with a whitish bloom when fresh. Attached laterally to wood by a small contracted point.",
    underside: "Fertile hymenial surface smooth to wrinkled or veined, lacking true gills or pores; grey-brown to reddish-brown, sometimes with a faint whitish dusting from spores when mature.",
    stem: "Absent or reduced to a small lateral attachment point fusing the fruitbody to the wood substrate.",
    fleshColor: "Translucent reddish-brown to amber; gelatinous and rubbery when fresh, cartilaginous-firm when partially dried, becoming hard, dark, and brittle when fully desiccated and rehydrating to the gelatinous state.",
    sporePrintColor: "White.",
    odor: "Mild, faintly earthy or fungal; not distinctive.",
    sizeCm: "Individual ears 2-10 cm (occasionally to 15 cm); thickness 1-3 mm; often fused in overlapping clusters spanning 20+ cm of substrate."
  },
  edibility: "edible-when-cooked",
  toxicityNotes: "Always cook before eating. Raw or undercooked wood ears (including the closely related Asian A. heimuer/A. polytricha used in Chinese cuisine) contain compounds with mild anticoagulant/antiplatelet activity (adenosine analogs and polysaccharides); habitual large raw consumption has been associated with prolonged bleeding times. Cook thoroughly and avoid in large quantities if on blood-thinning medication.",
  lookalikes: [
    { name: "American hardwood wood ear", scientific: "Auricularia angiospermarum", catalogId: "auricularia-angiospermarum", danger: "edible", keyFeatures: ["grows on hardwoods","nearly identical to wood ear"], distinguishingFeature: "Morphologically nearly identical but grows exclusively on hardwoods (oak, alder, maple, elder); previously lumped under A. auricula-judae; equally edible." },
    { name: "European jelly ear", scientific: "Auricularia auricula-judae", catalogId: "auricularia-auricula", danger: "edible", keyFeatures: ["restricted to Europe","especially on elder","genetically distinct from A. americana"], distinguishingFeature: "Old name historically applied to all North American material; true A. auricula-judae is now restricted to Europe (especially on elder, Sambucus) and is genetically distinct from A. americana." },
    { name: "Cloud ear / black fungus", scientific: "Auricularia polytricha (= A. cornea / A. heimuer complex)", catalogId: "auricularia-polytricha", danger: "edible", keyFeatures: ["thicker hairy/velvety upper surface","often greyer","not native to PNW"], distinguishingFeature: "Asian commercial species used in Chinese cooking; thicker, more conspicuously hairy/velvety upper surface, often greyer; not native to the PNW." },
    { name: "Amber jelly roll", scientific: "Exidia recisa", catalogId: "exidia-recisa", danger: "edible", keyFeatures: ["blob- or top-shaped","soft and squishy","on hardwood twigs","smaller than ear-shaped"], distinguishingFeature: "Smaller, more blob- or top-shaped (not ear-shaped), softer and more squishy, grows on hardwood twigs (especially willow and oak); edible but bland." },
    { name: "Leafy brain / black witch's butter", scientific: "Exidia glandulosa / Exidia nigricans", catalogId: "exidia-glandulosa", danger: "edible", keyFeatures: ["black brain-like folds","grows on hardwoods","tasteless"], distinguishingFeature: "Black, brain-like convoluted folds rather than ear shape; grows on hardwoods; edible but tasteless." },
    { name: "Witch's butter", scientific: "Tremella mesenterica", catalogId: "tremella-mesenterica", danger: "edible", keyFeatures: ["bright yellow to orange jelly","brain-like","parasitizes crust fungi on hardwoods"], distinguishingFeature: "Bright yellow to orange brain-like jelly; parasitizes crust fungi (Peniophora) on hardwoods rather than directly decaying wood." },
    { name: "Brown cup fungi", scientific: "Peziza spp. / Gyromitra perlata", danger: "GI-upset", keyFeatures: ["grows from soil/duff not wood","brittle/waxy flesh","some contain gyromitrin"], distinguishingFeature: "Grow terrestrially from soil or duff, not on wood; flesh is brittle/waxy rather than rubbery-gelatinous; some Gyromitra contain gyromitrin and should be avoided." },
    { name: "Wood ear mimics on conifer", scientific: "Pseudohydnum gelatinosum", catalogId: "pseudohydnum-gelatinosum", danger: "edible", keyFeatures: ["toothed/spiny surface","translucent white to grey","tongue-shaped on conifer wood"], distinguishingFeature: "Toothed (spiny) hymenial surface, translucent white to grey, tongue-shaped on conifer wood; edible jelly tooth, easy to separate by the soft spines." }
  ],
  culinary: {
    flavor: "Very mild, almost neutral in flavor; prized instead for its distinctive crunchy-gelatinous, slightly snappy texture that readily absorbs surrounding flavors and broths.",
    preparation: "Clean thoroughly (sediment lodges in folds), trim the tough attachment point, and slice into thin strips. Always cook: blanch 3-5 minutes or simmer/saute for at least 10 minutes. Classic uses include Chinese hot and sour soup, mu shu pork, stir-fries, Korean japchae, Vietnamese spring rolls, and braised dishes. Rehydrate dried specimens 20-30 minutes in warm water before cooking; reserve the soaking liquid for broth.",
    preservation: "Dehydrates exceptionally well due to its natural desiccation-tolerance; air-dry or dehydrate at 40-50 C until crisp and store airtight indefinitely (the standard commercial form). Rehydrates to near-fresh texture. Freezing is unnecessary and degrades texture; pickling in soy/vinegar brine is a good short-term option."
  },
  conservationNotes: "Not of conservation concern: widely distributed across coniferous forests of North America from Alaska through the Rockies and Pacific Northwest, common wherever suitable downed conifer wood persists. Strict-sense A. americana was only formally recircumscribed in 2013-2015, so older records under A. auricula-judae or A. auricula conflate it with the hardwood-loving A. angiospermarum. Reliant on coarse woody debris, so old-growth retention and snag/log preservation in managed forests support populations.",
  sources: [
    { name: "MushroomExpert.com - Auricularia americana by Michael Kuo", url: "https://www.mushroomexpert.com/auricularia_americana.html" },
    { name: "MykoWeb - Auricularia americana (California Fungi)", url: "https://www.mykoweb.com/CAF/species/Auricularia_americana.html" },
    { name: "Looney, Birkebak & Matheny 2013 - Systematics of the genus Auricularia with an emphasis on species from the southeastern United States (North American Fungi)", url: "https://pnwfungi.org/index.php/pnwfungi/article/view/1191" },
    { name: "Wu, Yuan, Kivlin, Bishop, Volk & Dai 2015 - Multi-locus phylogeny and taxonomy of the wood ear mushroom genus Auricularia", url: "https://www.sciencedirect.com/science/article/abs/pii/S1878614615000379" },
    { name: "Wikipedia - Auricularia", url: "https://en.wikipedia.org/wiki/Auricularia" },
    { name: "Forage Colorado - Foraging Wood Ear Mushrooms, Auricularia americana", url: "https://www.foragecolorado.com/post/foraging-wood-ear-mushrooms-auricularia-americana" }
  ],
  spores: { lengthMicrons: [12, 16.5], widthMicrons: [4, 5.5], shape: "allantoid (sausage-shaped)", ornamentation: "smooth", reaction: "hyaline in KOH", notes: "Reported ranges vary between authors: Kuo (MushroomExpert) gives 12-14 x 4-5.5 um, while Wu et al. 2015 and Wu et al. 2021 (Global Diversity and Updated Phylogeny) cite 14-16.5 x 4.5-5.4 um for A. americana sensu stricto; combined range presented here. Basidia cylindric, transversely 3-septate, ca. 55-75 x 4-5 um, embedded in a gelatinous matrix. Medullary zone absent in cross-section, a diagnostic separator from A. fuscosuccinea." },
  microhabitat: { slopeAspect: null, soilPh: null, soilTexture: null, moisturePreference: "Persistently humid microsites; underside/shaded sides of large-diameter downed conifer logs and snags where bark is retained and wood is in early-stage white rot. Strongly favors closed-canopy old-growth and mature stands with stable boundary-layer humidity.", indicatorPlants: ["Tsuga heterophylla", "Picea sitchensis", "Polystichum munitum", "Oplopanax horridus", "Rubus spectabilis", "bryophyte-draped coarse woody debris"], notes: "Substrate-obligate on gymnosperm coarse woody debris in PNW; not soil-associated, so edaphic variables (pH, texture) are not directly applicable. Highest fruiting density on logs in decay classes 2-3 with intact bark and sapwood still firm." },
  phenologyCues: [
    { cue: "Fruits within 24-72 hours of a soaking rain (>=10 mm/7 days) when air temperatures are 2-22 C", reliability: "strong" },
    { cue: "Same basidiocarps rehydrate and resume sporulation across multiple wet/dry cycles over several weeks", reliability: "strong" },
    { cue: "Spring (Apr-May) and fall (Oct-Nov) peaks in PNW coastal/montane forests following first sustained wet spells", reliability: "strong" },
    { cue: "Persistent overnight relative humidity >=75% under closed canopy promotes fresh flushes", reliability: "moderate" },
    { cue: "Appearance on conifer logs the season after a wet autumn that softens bark and initiates early white rot", reliability: "anecdotal" }
  ],
  bioactive: { compounds: ["acidic heteropolysaccharides (glucuronoxylomannans containing mannose, glucose, glucuronic acid, xylose)", "beta-glucans", "adenosine and adenosine analogs", "phenolic compounds", "ergosterol"], medicinalUses: ["antithrombin-mediated anticoagulant activity (documented in congeneric A. auricula/A. heimuer; A. americana presumed similar by genus-level chemistry but not directly assayed)", "antiplatelet / antithrombotic effects", "antioxidant activity", "immunomodulation", "hypolipidemic / cholesterol-lowering effects", "hypoglycemic activity"], toxinsOfNote: ["no characterized toxins; raw/undercooked consumption can prolong bleeding time via anticoagulant polysaccharides and adenosine analogs"], notes: "Most pharmacological work has been performed on Asian A. heimuer (long misidentified as A. auricula-judae) and on European A. auricula-judae; A. americana sensu stricto has not been independently characterized but is assumed to share the core polysaccharide chemistry based on phylogenetic proximity. Yoon et al. 2003 (Thrombosis Research 112:151-158) demonstrated that the glucuronic acid carboxyl groups are essential for anticoagulant activity via antithrombin." },
  dnaBarcode: { itsClade: "Clade B - Auricularia auricula-judae species complex (sensu Wu et al. 2021); A. americana forms a distinct well-supported lineage on gymnosperm substrates, sister to but separate from European A. auricula-judae and Asian A. heimuer", keyPaper: "Wu F, Tohtirjap A, Fan L-F, et al. 2021. Global Diversity and Updated Phylogeny of Auricularia (Auriculariales, Basidiomycota). Journal of Fungi 7(11):933. doi:10.3390/jof7110933. See also Looney, Birkebak & Matheny 2013 (North American Fungi 8:54-66) and Wu et al. 2015 (Mycological Progress 14:95).", notes: "Looney et al. 2013 first split North American material into 'coniferous unit' and 'deciduous unit' using ITS+rpb2; Wu et al. 2015 elevated the gymnosperm unit to A. americana sensu stricto and the angiosperm unit was later named A. angiospermarum. A. americana is genetically distant from European A. auricula-judae and from Asian commercial A. heimuer." },
  verification: { sourcesAgreeing: 4, lastVerified: "2026-05-23", consensus: "strong", disputeNotes: "Spore length ranges differ slightly between Kuo (MushroomExpert, 12-14 um) and Wu et al. 2015/2021 (14-16.5 um); the combined range is reported. Medicinal/bioactive claims rest on congeneric data (A. auricula-judae, A. heimuer) rather than direct assays of A. americana sensu stricto." }
}
