{
  id: "boletus-edulis",
  commonNames: ["King Bolete", "Porcini", "Cep", "Cepe", "Steinpilz", "Pacific King Bolete"],
  scientific: "Boletus edulis",
  family: "Boletaceae",
  order: "Boletales",
  trophicMode: "mycorrhizal",
  mycorrhizalPartners: ["Picea sitchensis", "Picea engelmannii", "Tsuga heterophylla", "Tsuga mertensiana", "Abies amabilis", "Abies procera", "Abies grandis", "Pseudotsuga menziesii", "Pinus contorta"],
  hostTrees: [
    { common: "Sitka spruce", scientific: "Picea sitchensis" },
    { common: "Engelmann spruce", scientific: "Picea engelmannii" },
    { common: "Western hemlock", scientific: "Tsuga heterophylla" },
    { common: "Mountain hemlock", scientific: "Tsuga mertensiana" },
    { common: "Pacific silver fir", scientific: "Abies amabilis" },
    { common: "Noble fir", scientific: "Abies procera" },
    { common: "Grand fir", scientific: "Abies grandis" },
    { common: "Douglas-fir", scientific: "Pseudotsuga menziesii" },
    { common: "Lodgepole/shore pine", scientific: "Pinus contorta" }
  ],
  substrate: "duff and mineral soil under conifers; often pushing up through moss, needle litter, or along forest road edges",
  habitat: "Ectomycorrhizal with a wide range of PNW conifers. The principal autumn PNW collection is Boletus edulis var. grandedulis (Pacific king bolete, Arora & Simonini 2008), fruiting in coastal Sitka spruce/western hemlock forests, subalpine true-fir and mountain hemlock stands, and in coastal lodgepole/shore pine on dunes. Frequently along logging roads, trail edges, and forest openings where soil is disturbed but mycorrhizal partners are intact. Note: the PNW spring 'kings' from montane true-fir and lodgepole pine stands are a separate species, Boletus rex-veris.",
  elevationM: { min: 0, max: 2200 },
  regionsPNW: ["Oregon Coast Range", "Washington Coast", "Olympics", "Cascades (both slopes)", "Vancouver Island", "British Columbia Coast", "Blue Mountains", "northeast Washington/Idaho Panhandle"],
  fruitingMonths: [8, 9, 10, 11, 12],
  peakMonths: [9, 10, 11],
  conditions: {
    minRain7d: 20,
    idealDaysSinceRain: [5, 14],
    tempRangeC: [8, 20],
    humidityMinPct: 75
  },
  identification: {
    cap: "Greasy to tacky when wet, dry and bald when dry; reddish-brown, chestnut, tan to dark brown, often paler near margin; convex becoming broadly convex to nearly flat; 7-30+ cm across",
    underside: "Tubes/pores; pore surface white and 'stuffed' (cottony, almost closed) when young, aging through pale yellow to olive-yellow; in var. grandedulis the mature pore surface becomes brownish to cinnamon brown; pores small, round, not bruising blue",
    stem: "Stout, club-shaped to bulbous when young, often elongating in age; whitish to pale tan, with fine raised white reticulation (netting) at least on the upper portion; 8-25 cm long x 3-10+ cm thick; firm and solid",
    fleshColor: "White, unchanging when cut (no blueing or other color change); firm in young specimens",
    sporePrintColor: "Olive-brown",
    odor: "Mild, pleasant, faintly nutty or mushroomy; taste mild (never bitter)",
    sizeCm: "Cap 7-30+ cm; stem 8-25 cm x 3-10 cm; frequently exceeds 1 kg in PNW var. grandedulis"
  },
  edibility: "choice",
  toxicityNotes: null,
  lookalikes: [
    { name: "Spring King Bolete", scientific: "Boletus rex-veris", catalogId: "boletus-rex-veris", danger: "edible", keyFeatures: ["spring/early summer fruiting","clustered","true-fir and lodgepole pine"], distinguishingFeature: "Fruits in spring/early summer (May-July) often gregariously or in clusters in montane true-fir and lodgepole pine stands; very similar microscopically and an equally choice edible" },
    { name: "Queen Bolete", scientific: "Boletus regineus", catalogId: "boletus-regineus", danger: "edible", keyFeatures: ["chocolate-brown cap with whitish bloom","mixed hardwood/conifer","oak and tanoak"], distinguishingFeature: "Darker, more chocolate-brown cap with a whitish bloom when young; associated with mixed hardwood/conifer woods (oak, tanoak); choice edible" },
    { name: "Butter-foot Bolete", scientific: "Boletus fibrillosus", catalogId: "boletus-fibrillosus", danger: "edible", keyFeatures: ["dry velvety dark-brown cap","brownish stem with darker reticulation"], distinguishingFeature: "Dry, finely hairy/velvety dark-brown cap; brownish (not whitish) stem with darker reticulation; edible" },
    { name: "Admirable Bolete", scientific: "Aureoboletus mirabilis", catalogId: "aureoboletus-mirabilis", danger: "edible", keyFeatures: ["reddish-brown shaggy dry cap","yellow pores","on rotten hemlock logs"], distinguishingFeature: "Dark reddish-brown shaggy/fibrillose dry cap, yellow pores, often fruits on rotten hemlock logs (saprotrophic-leaning); edible" },
    { name: "Bitter Bolete", scientific: "Tylopilus felleus", catalogId: "tylopilus-felleus", danger: "inedible", keyFeatures: ["pore surface pink with age","dark coarse stem reticulation","pink spore print","intensely bitter"], distinguishingFeature: "Pore surface becomes pink with age, dark brown coarse reticulation on stem, pink spore print, intensely bitter taste; primarily eastern N. America but worth checking - a nibble test reveals it" },
    { name: "Red-pored Bolete", scientific: "Rubroboletus pulcherrimus", catalogId: "rubroboletus-pulcherrimus", danger: "toxic", keyFeatures: ["bright red to orange-red pores","flesh stains blue instantly","reddish stem reticulation"], distinguishingFeature: "Bright red to orange-red pore surface, flesh stains blue instantly when cut, stem with reddish reticulation; causes severe GI distress (one historical fatality)" },
    { name: "Bitter Beach Bolete", scientific: "Caloboletus rubripes", catalogId: "caloboletus-rubripes", danger: "inedible", keyFeatures: ["yellow pores bruise blue","red stem base","intensely bitter","conifers on West Coast"], distinguishingFeature: "Yellow pore surface bruising blue, red base of stem, intensely bitter taste; associated with conifers on the West Coast" },
    { name: "Zeller's Bolete", scientific: "Xerocomellus zelleri", catalogId: "xerocomellus-zelleri", danger: "edible", keyFeatures: ["dry black to dark-brown cap","red marginal cracks","yellow pores","slender stem"], distinguishingFeature: "Much smaller, dry black to dark-brown cap with red marginal cracks, yellow pores, slender stem; edible but mediocre" }
  ],
  culinary: {
    flavor: "Rich, deeply savory and nutty with strong umami; the benchmark gourmet wild mushroom and the European porcini of commerce",
    preparation: "Slice and saute fresh in butter or olive oil with garlic; use in risotto, pasta sauces, omelets, soups, and on steaks. Younger 'buttons' (with white stuffed pores) are prime; remove tubes in older specimens as they go slimy when cooked. Always inspect for fly larvae - cut lengthwise.",
    preservation: "Excellent dried (the classic preservation method): slice 5-8 mm thick and dehydrate at 40-50 C until cracker-dry, then store airtight; rehydrated dried kings have an intensified flavor used in stocks and sauces. Also good frozen after a dry saute. Pickling and porcini powder/salt are common."
  },
  conservationNotes: "IUCN Red List: Least Concern globally. Commercially harvested at significant volume from PNW national forests (especially in Oregon and Washington), with permit systems administered by USFS districts. Studies indicate harvest by careful plucking does not appear to suppress future fruiting, but soil disturbance, raking, and habitat loss (clearcut/old-growth removal) reduce mycorrhizal partners. Sensitive to drought trends in the PNW.",
  sources: [
    { name: "MushroomExpert.com - Boletus edulis (Michael Kuo)", url: "https://www.mushroomexpert.com/boletus_edulis.html" },
    { name: "MykoWeb - California Fungi: Boletus edulis var. grandedulis", url: "https://www.mykoweb.com/CAF/species/Boletus_edulis.html" },
    { name: "MushroomExpert.com - Boletus edulis var. grandedulis", url: "https://www.mushroomexpert.com/boletus_edulis_grandedulis.html" },
    { name: "Salish Mushrooms - PNW Boletes overview", url: "https://salishmushrooms.com/boletes/" },
    { name: "Arora, D. & Simonini, G. (2008) - Boletus edulis var. grandedulis, a new species description from western North America. Economic Botany 62(3): 374.", url: "https://link.springer.com/article/10.1007/s12231-008-9038-3" },
    { name: "Pilz, D., Molina, R., et al. (2003) - Ecology and Management of Commercially Harvested Mushrooms (USDA PNW-GTR-576)", url: "https://www.fs.fed.us/pnw/pubs/pnw_gtr576.pdf" }
  ],
  spores: { lengthMicrons: [12, 17], widthMicrons: [4, 7], shape: "subfusiform to ellipsoid (spindle-shaped)", ornamentation: "smooth", reaction: "inamyloid in Melzer's reagent; ochraceous in KOH", notes: "Spore print olive-brown. Reported ranges across sources: 12-17 x 5-7 microns (Wikipedia/Kuo), 14.5-17.5 x 4-6 microns (Monaco Nature Enc.), up to 12-20 x 4-7 microns reported for the genus. Pleurocystidia thin-walled, fusoid-ventricose, 30-45 x 7-10 microns. Hyphae lack clamp connections." },
  microhabitat: { slopeAspect: null, soilPh: [3.5, 5.5], soilTexture: "sandy to loamy, well-drained mineral soil with conifer duff/humus layer", moisturePreference: "consistently moist but not waterlogged; avoids both droughty and saturated soils", indicatorPlants: ["Picea sitchensis", "Tsuga heterophylla", "Pseudotsuga menziesii", "Vaccinium ovatum", "Vaccinium parvifolium", "Gaultheria shallon", "Hylocomium splendens (step moss)", "Kindbergia oregana"], notes: "Prefers acidic to slightly acidic soils; mean substrate pH ~4.2 in upper 20 cm, with extremes near 3.5 (Funginomi/European data). Tolerates alkaline parent material only where surface horizons are acidified. Often along disturbed edges (road cuts, trail margins) where mineral soil is exposed under intact conifer canopy." },
  phenologyCues: [
    { cue: "First substantial autumn rain event (>=2 inches over a week) following a warm-dry summer, with subsequent night temperatures dropping into the 7-12 C range", reliability: "strong" },
    { cue: "Soil temperatures at 10 cm depth between approximately 10-15 C", reliability: "moderate" },
    { cue: "5-14 day lag between soaking rain and fruiting flush", reliability: "strong" },
    { cue: "Appearance of Cantharellus formosus and Hydnum species in the same forest type often precedes or coincides with king bolete flushes", reliability: "moderate" },
    { cue: "Coastal fog/marine layer persistence in Sitka spruce zone correlates with extended fruiting windows", reliability: "anecdotal" },
    { cue: "Visible 'mushrumps' (heaved duff/needle litter) along road shoulders and trail edges", reliability: "anecdotal" }
  ],
  bioactive: { compounds: ["beta-glucans (up to ~46.6 g/100 g DW)", "alpha-glucans (~3.9 g/100 g DW)", "ergosterol (vitamin D2 precursor, ~226 mg/100 g extract)", "triterpenoids", "polyphenols and flavonoids", "caffeoyltryptophan", "lycopene and carotenoids", "unsaturated fatty acids", "ergothioneine"], medicinalUses: ["immunomodulatory (beta-glucan mediated)", "antioxidant", "antitumor (in vitro/in vivo studies)", "antimicrobial and antiviral activity reported", "hepatoprotective", "anti-hypercholesterolemic", "anti-diabetic (alpha-glucosidase/alpha-amylase inhibition)"], toxinsOfNote: [], notes: "No known toxins; B. edulis is choice edible. However, the species is a notable bioaccumulator of heavy metals (Cd, Pb, Hg, Cs-137 radiocesium) from contaminated substrates - relevant for harvests near roads, mine tailings, or post-Chernobyl/Fukushima fallout zones. Raw or undercooked specimens may cause mild GI upset in sensitive individuals." },
  dnaBarcode: { itsClade: "Boletus edulis sensu lato species complex (Boletus section Boletus); PNW collections fall within the broader B. edulis clade but include the morphologically distinct var. grandedulis. The complex shows surprisingly low genetic variability across a wide intercontinental range.", keyPaper: "Dentinger BTM, Ammirati JF, Both EE, Desjardin DE, Halling RE, Henkel TW, Moreau PA, Nagasawa E, Soytong K, Taylor AFS, Watling R, Moncalvo JM, McLaughlin DJ (2010). Molecular phylogenetics of porcini mushrooms (Boletus section Boletus). Molecular Phylogenetics and Evolution 57(3): 1276-1292. doi:10.1016/j.ympev.2010.10.004", notes: "Dentinger et al. (2010) using ITS + nLSU + tef1 confirmed B. edulis as a wide-ranging Holarctic species complex including formerly separate taxa (B. betulicola, B. chippewaensis, B. persoonii, B. quercicola, B. venturii) as conspecific, while distinguishing B. pinophilus, B. reticulatus/aestivalis, and B. aereus as separate species. Beugelsdijk et al. (2008) similarly noted low ITS variability. PNW var. grandedulis remains a morphological variant within the B. edulis ITS clade rather than a distinct molecular species." },
  verification: { sourcesAgreeing: 5, lastVerified: "2026-05-23", consensus: "strong", disputeNotes: "Taxonomic rank of var. grandedulis is debated: Arora & Simonini (2008) described it as a variety based on morphology (mature brown pore surface, large size), but ITS data place it within typical B. edulis without distinct clade support. Some authors treat it as a regional ecotype rather than a formal variety." }
}
