{
  id: "craterellus-tubaeformis",
  commonNames: ["Yellowfoot", "Winter Chanterelle", "Funnel Chanterelle", "Trumpet Chanterelle", "Yellow Foot", "Yellow Legs"],
  scientific: "Craterellus tubaeformis",
  family: "Cantharellaceae",
  order: "Cantharellales",
  trophicMode: "mycorrhizal",
  mycorrhizalPartners: ["Tsuga heterophylla", "Pseudotsuga menziesii", "Picea sitchensis"],
  hostTrees: [
    { common: "Western hemlock", scientific: "Tsuga heterophylla" },
    { common: "Douglas-fir", scientific: "Pseudotsuga menziesii" },
    { common: "Sitka spruce", scientific: "Picea sitchensis" }
  ],
  substrate: "Well-decayed coarse woody debris (rotten conifer logs) and mossy duff; frequently fruits directly from moss-covered, well-rotted logs and stumps",
  habitat: "Ectomycorrhizal, strongly associated with western hemlock in cool, wet conifer forests of the PNW; rarely encountered in stands lacking a hemlock component. Volume of well-decayed coarse woody debris is the strongest predictor of occurrence in stands <100 yr old (88% of sporocarps fruit from well-decayed CWD per Trappe 2004). Favors mossy, shaded microsites in cold conifer bogs, riparian flats, and old second-growth. Hydnum spp. presence is a good co-occurrence indicator.",
  elevationM: { min: 0, max: 1200 },
  regionsPNW: ["Oregon Coast Range", "Cascades west slope", "Olympic Peninsula", "Puget lowlands", "Vancouver Island", "BC South Coast", "Northern California redwood belt"],
  fruitingMonths: [9, 10, 11, 12, 1, 2],
  peakMonths: [11, 12],
  conditions: {
    minRain7d: 30,
    idealDaysSinceRain: [3, 10],
    tempRangeC: [2, 12],
    humidityMinPct: 85
  },
  identification: {
    cap: "Yellowish-brown to dark brown, sometimes greyish with age; 2-7 cm across; initially convex, soon becoming deeply depressed, funnel- or trumpet-shaped, frequently perforated at the center (hollow down through the stem); margin wavy and inrolled when young; surface dry to faintly waxy, bald to finely scaly",
    underside: "False gills - blunt, widely spaced, forked decurrent ridges/veins with cross-veins (not true gills); yellow to pale yellow when young, developing distinctive grayish to lilac-gray shades with age - a key field mark",
    stem: "Bright yellow to orange-yellow, hollow throughout, smooth to longitudinally grooved, often twisted or compressed, sometimes appearing as a pair of legs; 2-9 cm long x 0.3-1 cm thick; no ring; base sometimes swollen",
    fleshColor: "Pale yellow to whitish, thin, brittle; does not change color when cut",
    sporePrintColor: "White to cream, sometimes faintly pale yellow or salmon-tinted",
    odor: "Mild, faintly fruity or earthy; taste mild",
    sizeCm: "Cap 2-7 cm; stem 2-9 cm long x 0.3-1 cm thick; total height 3-10 cm"
  },
  edibility: "choice",
  toxicityNotes: "Reported to bioaccumulate heavy metals - avoid collecting from roadsides, industrial sites, or contaminated soils. Always cook thoroughly.",
  lookalikes: [
    { name: "Deadly Webcap", scientific: "Cortinarius rubellus", catalogId: "cortinarius-rubellus", danger: "deadly", keyFeatures: ["true rust-brown gills","rusty-brown spore print","cobwebby cortina","scaly stem"], distinguishingFeature: "True crowded rust-brown gills (not blunt ridges), rusty-brown spore print, cortina (cobwebby partial veil) when young, scaly orange-brown stem - causes irreversible kidney failure; habitat overlap in mossy conifer woods" },
    { name: "Jelly Baby", scientific: "Leotia lubrica", catalogId: "leotia-lubrica", danger: "inedible", keyFeatures: ["smooth gelatinous underside","olive-yellow head","rubbery","ascomycete"], distinguishingFeature: "Smooth gelatinous underside with no ridges/veins; convex olive-yellow head not funnel-shaped; rubbery texture; ascomycete" },
    { name: "False Chanterelle", scientific: "Hygrophoropsis aurantiaca", catalogId: "hygrophoropsis-aurantiaca", danger: "GI-upset", keyFeatures: ["forked orange gills","deep orange throughout","solid stem","on woody debris"], distinguishingFeature: "True thin forked orange gills (not blunt ridges); deep orange throughout; solid stem (not hollow); often on woody debris but more orange than yellow-brown" },
    { name: "Smooth Chanterelle", scientific: "Cantharellus lateritius / Craterellus ignicolor", catalogId: "cantharellus-lateritius", danger: "edible", keyFeatures: ["orange-yellow throughout","smooth hymenium","eastern/southern range"], distinguishingFeature: "Orange-yellow throughout (not brown cap with yellow stem); nearly smooth or weakly ridged hymenium; eastern/southern distribution mostly" },
    { name: "Pig's Ear / Violet Chanterelle", scientific: "Gomphus clavatus", catalogId: "gomphus-clavatus", danger: "edible", keyFeatures: ["violet ridged hymenium","club-shaped","clustered in conifer duff"], distinguishingFeature: "Larger, club-shaped to clavate; purple to violet tones on ridged hymenium; thicker fleshier stipe; cespitose growth in conifer duff" }
  ],
  culinary: {
    flavor: "Mild, delicately earthy and slightly fruity; less pungent than golden chanterelles but excellent texture; absorbs surrounding flavors well",
    preparation: "Brush clean - do not soak (hollow stems retain water). Dry-saute briefly to drive off moisture, then finish in butter with shallots, garlic, thyme, or cream. Excellent in soups, cream sauces, risotto, omelets, and game dishes. Their small size makes them ideal whole as a garnish.",
    preservation: "Dries exceptionally well - one of the best chanterelles for dehydration, retaining flavor and rehydrating to good texture. Can also be sauteed and frozen, pickled, or duxelle'd. Dried specimens keep flavor for over a year."
  },
  conservationNotes: "IUCN Red List status: Least Concern. Locally abundant across the PNW. Habitat dependent on retention of well-decayed coarse woody debris and mature hemlock cover; clearcutting and removal of down wood significantly reduces fruiting. Trappe (2004) recommends managing for downed log retention in second-growth stands to sustain populations. Genetic evidence suggests western North American, eastern North American, and European populations may represent distinct species.",
  sources: [
    { name: "MushroomExpert.com - Craterellus tubaeformis (Kuo, 2015)", url: "https://www.mushroomexpert.com/craterellus_tubaeformis.html" },
    { name: "MykoWeb - California Fungi: Craterellus tubaeformis", url: "https://www.mykoweb.com/CAF/species/Craterellus_tubaeformis.html" },
    { name: "Trappe, M.J. (2004) - Habitat and host associations of Craterellus tubaeformis in northwestern Oregon, Mycologia 96(3):498-509", url: "https://research.fs.usda.gov/treesearch/27151" },
    { name: "USDA PNW Research Station PDF - Trappe 2004", url: "https://www.fs.usda.gov/pnw/pubs/journals/pnw_2004_trappe001.pdf" },
    { name: "Wikipedia - Craterellus tubaeformis", url: "https://en.wikipedia.org/wiki/Craterellus_tubaeformis" },
    { name: "Northern Bushcraft - Winter Chanterelle in British Columbia", url: "https://northernbushcraft.com/mushrooms/_winter_chanterelle/bc.htm" }
  ],
  spores: { lengthMicrons: [9, 11], widthMicrons: [6, 8], shape: "ellipsoid", ornamentation: "smooth, thin-walled with minutely granular homogeneous contents", reaction: "hyaline (non-reactive) in KOH; non-amyloid", notes: "Basidia 4-sterigmate, 50-65 microns long; spore print white to cream, sometimes pale salmon-tinted; European 'infundibuliformis' was historically separated by spore size but molecular data does not support the distinction (per Dahlman et al. 2000)" },
  microhabitat: { slopeAspect: "north-facing and shaded aspects favored; cool, low-insolation microsites", soilPh: [3.5, 5.5], soilTexture: "humus-rich, well-drained but moisture-retentive forest floor over decomposed coarse woody debris; thick moss/duff layer", moisturePreference: "consistently moist to saturated; thrives in mossy seeps, riparian flats, and cold conifer bogs but not in standing water", indicatorPlants: ["Sphagnum spp.", "feather mosses (Hylocomium splendens, Rhytidiadelphus loreus, Kindbergia oregana)", "Vaccinium parvifolium", "Vaccinium ovatum", "Gaultheria shallon", "Oxalis oregana", "Polystichum munitum", "Blechnum spicant"], notes: "Single best field indicator is thick moss carpets around old, well-decayed conifer stumps in western hemlock or Sitka spruce stands. In conifer bogs associates with ericaceous understory amid sphagnum. Hydnum repandum/umbilicatum co-occurrence is a strong positive signal." },
  phenologyCues: [
    { cue: "First sustained autumn rains (>=30 mm cumulative over 7 days) after night temperatures drop below 10C", reliability: "strong" },
    { cue: "Co-fruiting with Hydnum repandum/umbilicatum (hedgehogs) in the same mossy microsites", reliability: "strong" },
    { cue: "Fruits 2-4 weeks later than golden chanterelles (Cantharellus formosus) in the same forest", reliability: "strong" },
    { cue: "Persistent fruiting through light frosts and even snow dustings as long as ground is unfrozen", reliability: "moderate" },
    { cue: "Second/third flush following warm rain events in midwinter (Dec-Feb) along the coast", reliability: "moderate" },
    { cue: "Mossy old stumps showing fresh fruiting after 3-10 days following >25 mm rain", reliability: "moderate" },
    { cue: "Bumper years correlated with cool, wet summers preceding the fruiting season", reliability: "anecdotal" }
  ],
  bioactive: { compounds: ["ergosterol and ergosterol peroxide", "beta-glucans (cell-wall polysaccharides)", "phenolic antioxidants", "vitamin D2 precursors (ergocalciferol after UV exposure)", "free amino acids contributing to umami"], medicinalUses: ["traditional/folk use as a tonic and nutritive food in Scandinavia (no strong clinical evidence)", "antioxidant activity demonstrated in vitro", "preliminary immunomodulatory activity attributed to beta-glucans"], toxinsOfNote: ["heavy-metal bioaccumulation (cadmium, mercury, lead) when fruiting on contaminated substrates - main practical concern"], notes: "Not known to produce acute mycotoxins; raw consumption gives a peppery taste and is generally discouraged. Always cook thoroughly. Medicinal claims are largely traditional/preliminary rather than clinically established." },
  dnaBarcode: { itsClade: "Western North American clade (provisionally 'Craterellus neotubaeformis', Craterellus sp. 02 sensu Kuo), distinct from the European + eastern North American clade that retains the epithet C. tubaeformis sensu stricto (type from Sweden); ITS and LSU rDNA both recover the geographic split, with at least one anomalous Quebec/Belgian subclade complicating the picture", keyPaper: "Guo-ying Z., Liang G., Lin L. & He L. (2011) 'rDNA internal transcribed spacer sequence analysis of Craterellus tubaeformis from North America and Europe', Canadian Journal of Microbiology 57: 29-32; building on Dahlman, Danell & Spatafora (2000) Mycological Research 104: 388-394", notes: "Oregon Biodiversity Information Center flagged 'Craterellus neotubaeformis' as a provisional name for western NA material in 2017 but the formal description remained unpublished. Hollow stipe is a synapomorphy supporting placement in Craterellus rather than Cantharellus. Recommended barcode markers: ITS1-5.8S-ITS2 and nuc 28S rDNA D1-D2." },
  verification: { sourcesAgreeing: 6, lastVerified: "2026-05-23", consensus: "strong", disputeNotes: "Strong consensus on morphology, ecology, and edibility. Active taxonomic dispute over whether western North American populations represent a distinct species ('C. neotubaeformis') from European/eastern NA C. tubaeformis sensu stricto - molecular phylogenies (LSU, ITS) recover the split but a formal species description has not been published; one 2011 ITS study also recovered an anomalous Quebec+Belgium subclade, indicating the complex is not fully resolved." }
}
