{
  id: "helvella-vespertina",
  commonNames: ["Western Black Elfin Saddle", "Western Fluted Black Elfin Saddle", "Black Elfin Saddle (western)", "Fluted Black Helvella"],
  scientific: "Helvella vespertina",
  family: "Helvellaceae",
  order: "Pezizales",
  trophicMode: "mycorrhizal",
  mycorrhizalPartners: ["Pseudotsuga menziesii", "Pinus contorta", "Pinus ponderosa", "Tsuga heterophylla", "Picea sitchensis", "Abies grandis"],
  hostTrees: [
    { common: "Douglas-fir", scientific: "Pseudotsuga menziesii" },
    { common: "Lodgepole/Shore pine", scientific: "Pinus contorta" },
    { common: "Ponderosa pine", scientific: "Pinus ponderosa" },
    { common: "Western hemlock", scientific: "Tsuga heterophylla" },
    { common: "Sitka spruce", scientific: "Picea sitchensis" },
    { common: "Grand fir", scientific: "Abies grandis" }
  ],
  substrate: "Mineral soil and conifer duff under living conifers; forms ectomycorrhizal associations with Douglas-fir, pines, hemlock, spruce, and other conifers. Frequent in disturbed soil along trail edges, road cuts, landscaped areas with planted conifers, and occasionally on burnt or recently disturbed ground.",
  habitat: "Scattered, gregarious, or cespitose (clustered) on the ground under conifers - especially Douglas-fir and pine - in coastal forests, mixed conifer forests, urban parks, cemeteries, and landscape plantings where conifers are present. A late-season species: most abundant from mid-fall through early winter, often continuing to fruit into December and January after the main chanterelle and bolete flushes have ended. Tolerates cool, wet conditions and short day length better than most fall mushrooms.",
  elevationM: { min: 0, max: 1500 },
  regionsPNW: ["Oregon Coast Range", "Cascade Range (west slope)", "Puget Sound lowlands", "Olympic Peninsula", "Willamette Valley conifer plantings", "southwestern British Columbia", "Vancouver Island", "northern California coast", "urban Seattle/Portland conifer plantings", "Siskiyou Mountains"],
  fruitingMonths: [10, 11, 12, 1],
  peakMonths: [11, 12],
  conditions: {
    minRain7d: 15,
    idealDaysSinceRain: [3, 10],
    tempRangeC: [2, 14],
    humidityMinPct: 75
  },
  identification: {
    cap: "Irregularly saddle-shaped to two- or three-lobed, often folded, contorted, or convoluted; 2-6 cm wide and 2-5 cm tall; upper (fertile) surface smooth to undulating, dark gray, charcoal, slate-black, to nearly jet black, sometimes paler gray-brown when young or sun-bleached; margin of the cap is usually fused or appressed to the upper stem in places (not free like a Verpa)",
    underside: "Sterile underside paler than the fertile surface - whitish, pale gray, to medium gray, smooth to minutely pruinose (NOT pubescent/fuzzy like Helvella maculata); not pitted or fluted",
    stem: "Distinctively deeply fluted, ribbed, and pocketed (lacunose) with prominent longitudinal ridges and chambers (lacunae) running the full length; 3-10 cm tall x 1-3 cm thick; whitish to pale gray when young, darkening to gray or grayish-black with age; interior chambered/hollow within the fluting; the deep stem ribs are a key genus character for Helvella",
    fleshColor: "Thin, brittle, waxy; whitish to pale gray throughout, not changing on exposure",
    sporePrintColor: "White to pale cream",
    odor: "Mild and indistinct, not distinctive; taste mild but reportedly chewy and bland",
    sizeCm: "Total height 5-15 cm; cap 2-6 cm wide; stem 3-10 cm long x 1-3 cm thick"
  },
  edibility: "edible-with-caution",
  toxicityNotes: "Contains gyromitrin / monomethylhydrazine (MMH)-type hydrazine compounds similar to those in false morels (Gyromitra esculenta). MMH is acutely toxic, hepatotoxic, neurotoxic, and a known animal carcinogen; it is also volatile. RAW or undercooked specimens can cause vomiting, headache, vertigo, hemolysis, and in severe cases liver/kidney damage or death. MUST be cooked thoroughly - parboiled in plenty of water with the cooking liquid discarded, then sauteed - and ALWAYS prepared with strong ventilation (open windows or outdoors) because MMH is released as vapor during cooking and is inhalation-toxic to the cook. Toxin content is variable between collections and individuals and tolerance differs widely between people. Cumulative toxicity is possible with repeated meals. Many modern authorities (MykoWeb 'Toxic Fungi of Western North America', Trudell & Ammirati, UBC 'Mushrooms Up!') recommend AVOIDING this species entirely. Never serve to children, pregnant individuals, the elderly, or first-time mushroom eaters. Do not consume with alcohol.",
  lookalikes: [
    { name: "Oak-loving Elfin Saddle", scientific: "Helvella dryophila", catalogId: "helvella-dryophila", danger: "edible-with-caution", keyFeatures: ["mycorrhizal with oaks","oak woodland habitat"], distinguishingFeature: "Nearly identical in appearance but ectomycorrhizal with oaks (Quercus spp.) rather than conifers - habitat is the single most reliable separator; range largely south of the main PNW conifer zone but overlaps in southern Oregon and California oak woodlands; carries the same MMH toxicity concerns" },
    { name: "European Elfin Saddle", scientific: "Helvella lacunosa", catalogId: "helvella-lacunosa", danger: "edible-with-caution", keyFeatures: ["European species rare in west","separable only by DNA/geography"], distinguishingFeature: "True H. lacunosa is a European species now considered absent or very rare in western North America; western collections previously called H. lacunosa are nearly all H. vespertina (with conifers) or H. dryophila (with oaks); separable reliably only by DNA and geography" },
    { name: "Fluted White Elfin Saddle", scientific: "Helvella crispa", catalogId: "helvella-crispa", danger: "edible-with-caution", keyFeatures: ["fluted lacunose stem","creamy white not black","fuzzy cap underside","inrolled young margins"], distinguishingFeature: "Same deeply fluted lacunose stem and saddle-shaped cap, but cap and stem are creamy white to pale buff (NOT black/gray); cap underside is finely pubescent/fuzzy; cap margins typically inrolled when young; also contains MMH-type toxins and requires the same precautions" },
    { name: "Fluted Brown Elfin Saddle", scientific: "Helvella maculata", catalogId: "helvella-maculata", danger: "edible-with-caution", keyFeatures: ["grayish-brown mottled cap","free margin","fuzzy whitish underside","deeply ribbed stem"], distinguishingFeature: "Cap grayish-brown to medium brown, sometimes mottled, with a margin that is NOT attached to the stipe (free margin); underside whitish and distinctly pubescent/fuzzy; deeply ribbed white to grayish-brown stem; same MMH concerns" },
    { name: "Compressed Elfin Saddle", scientific: "Helvella compressa", catalogId: "helvella-compressa", danger: "edible-with-caution", keyFeatures: ["small and slender","faintly grooved cylindrical stem","small smooth gray saddle"], distinguishingFeature: "Much smaller and slenderer; stem cylindrical and only faintly grooved (NOT deeply lacunose); cap small, smooth, gray to brown saddle; same MMH concerns" },
    { name: "False Morel / Brain Mushroom", scientific: "Gyromitra esculenta", catalogId: "gyromitra-esculenta", danger: "deadly", keyFeatures: ["reddish-brown brain-like cap","stout chambered stem","spring fruiting","high gyromitrin"], distinguishingFeature: "Cap reddish-brown to chestnut, brain-like with tightly convoluted lobes (NOT a clean saddle); stem stout, whitish, chambered internally with folds but NOT deeply fluted/lacunose on the outside; primarily a spring species (April-June) rather than fall/winter; contains higher concentrations of gyromitrin/MMH and is potentially lethal" },
    { name: "Snowbank False Morel", scientific: "Gyromitra montana (= Gyromitra gigas)", danger: "toxic", keyFeatures: ["tan brain-like lobed cap","thick chambered stem","near melting snow","not saddle-shaped"], distinguishingFeature: "Robust, stocky; tan to reddish-brown brain-like lobed cap; thick whitish stem chambered internally; fruits near melting snow in spring at higher elevations; not saddle-shaped and not deeply lacunose-stemmed" },
    { name: "Hooded False Morel", scientific: "Gyromitra infula", catalogId: "gyromitra-infula", danger: "toxic", keyFeatures: ["saddle-shaped reddish-brown cap","smooth/faintly grooved stem","fall on rotten wood"], distinguishingFeature: "Saddle-shaped cap somewhat similar in outline, but cap reddish-brown to chestnut (NOT black/gray) and smooth-to-folded rather than convoluted; stem smooth or only faintly grooved, NOT deeply fluted; fall fruiting on rotten wood and conifer debris; contains MMH" }
  ],
  culinary: {
    flavor: "Mild, chewy, and bland according to Arora and other PNW authors; flavor is not a compelling reason to risk the toxicity. Texture is described as rubbery to slightly crisp after thorough cooking",
    preparation: "If consumed despite cautions: parboil twice in large volumes of water for 5-10 minutes each time, discarding ALL cooking liquid between parboils, then saute thoroughly in butter or oil for an additional 10-15 minutes. ALWAYS cook outdoors or with windows open and strong ventilation - MMH vapor released during cooking is itself toxic by inhalation. Serve in small portions; never on consecutive days; never to children, pregnant individuals, or first-time eaters. Discard any specimens that smell off or are past their prime. Most modern PNW authorities recommend avoiding this species entirely",
    preservation: "Drying is sometimes practiced for Helvella, but drying does NOT reliably eliminate MMH and may concentrate the toxin by weight; rehydration water must always be discarded. Given the toxicity profile, preservation is not recommended"
  },
  conservationNotes: "Common to locally abundant under conifers throughout its range in the PNW, both in wild forests and in urban/suburban conifer plantings; not of conservation concern. The species was formally described only in 2013 (Nguyen & Vellinga) after molecular work showed that western North American 'Helvella lacunosa' actually comprises multiple distinct species, of which H. vespertina is the conifer-associated western entity. Often parasitized by the bonnet mold Hypomyces cervinigenus, which produces tan to whitish growth over the fruiting body.",
  sources: [
    { name: "MykoWeb - California Fungi: Helvella vespertina", url: "https://www.mykoweb.com/CAF/species/Helvella_vespertina.html" },
    { name: "Nguyen, N.H., Landeros, F., Garibay-Orijel, R., Hansen, K. & Vellinga, E.C. (2013) - The Helvella lacunosa species complex in western North America: cryptic species, misapplied names and parasites. Mycologia 105(5): 1275-1286", url: "https://nature.berkeley.edu/brunslab/papers/nguyen2013b.pdf" },
    { name: "Burke Herbarium Image Collection - Helvella vespertina", url: "https://burkeherbarium.org/imagecollection/taxon.php?Taxon=Helvella+vespertina" },
    { name: "UBC Mushrooms Up! Edible and Poisonous Species of Coastal BC and the PNW - Helvella vespertina", url: "https://www.zoology.ubc.ca/~biodiv/mushroom/H_vespertina.html" },
    { name: "Santa Cruz Mycoflora Project - Genus Helvella", url: "https://scmycoflora.org/genera/helvella/helvella-species.php" },
    { name: "Salish Mushrooms - Helvella (Elfin Saddles) PNW Guide", url: "https://salishmushrooms.com/mushrooms/helvella/" },
    { name: "MykoWeb - Toxic Fungi of Western North America (Michael W. Beug)", url: "https://www.mykoweb.com/TFWNA" },
    { name: "Wikipedia - Helvella lacunosa (taxonomic background and western species split)", url: "https://en.wikipedia.org/wiki/Helvella_lacunosa" },
    { name: "Wikipedia - Monomethylhydrazine (MMH toxicity and gyromitrin)", url: "https://en.wikipedia.org/wiki/Monomethylhydrazine" },
    { name: "Trudell, S. & Ammirati, J. (2009) - Mushrooms of the Pacific Northwest, Timber Press Field Guide", url: "https://www.timberpress.com/books/mushrooms_pacific_northwest/trudell/9780881929355" }
  ],
  spores: { lengthMicrons: [17, 22], widthMicrons: [11, 14], shape: "broadly ellipsoid", ornamentation: "smooth (under light microscopy), each spore with a single large central oil droplet (guttule)", reaction: "hyaline in KOH and in water; non-amyloid (inoperculate ascus)", notes: "Asci 8-spored, ~250-300 x 15-20 microns, operculate, non-amyloid (J-) in Melzer's reagent. Paraphyses filiform with clavate to subcapitate apices, often with brown granular contents. Spores of H. vespertina average slightly larger than H. dryophila (15-20 x 10-13 microns) - one of few microscopic features separating the two cryptic conifer/oak siblings of the western H. lacunosa complex" },
  microhabitat: { slopeAspect: null, soilPh: [4.5, 6.5], soilTexture: "well-drained mineral soils with conifer duff/needle litter overlay; tolerant of compacted disturbed soils along roads and trails, also gravelly fill and landscape mulch in urban conifer plantings", moisturePreference: "consistently moist but not waterlogged; fruits during cool wet PNW fall/early winter rains after soils have been thoroughly recharged; tolerates short freezes that would damage most fleshy fungi", indicatorPlants: ["Pseudotsuga menziesii", "Pinus contorta", "Pinus ponderosa", "Tsuga heterophylla", "Picea sitchensis", "Mahonia nervosa", "Gaultheria shallon", "Polystichum munitum", "Hypnum / Kindbergia moss mats"], notes: "Strongly associated with mature to second-growth conifer stands but also abundant in human-modified microhabitats: cemetery plantings, urban Douglas-fir/pine boulevards, conifer-dominated arboreta, and disturbed road cuts. The species has been documented on recently burnt ground as well. Often fruits in moss carpets adjacent to host root systems" },
  phenologyCues: [
    { cue: "Sustained autumn rainfall accumulating >=40 mm over the preceding 10-14 days, after which fruiting bodies emerge 5-10 days following soaking rain", reliability: "strong" },
    { cue: "Daytime soil temperatures dropping into the 4-12 C range at 5 cm depth - the species fruits later than most PNW ectomycorrhizal mushrooms and tolerates near-freezing nights", reliability: "strong" },
    { cue: "First killing frost or extended cold snap of the fall, which often triggers a noticeable flush 1-2 weeks afterward in coastal lowland conifer plantings", reliability: "moderate" },
    { cue: "Continues fruiting after chanterelles (Cantharellus formosus) and king boletes (Boletus edulis) have finished for the season - functions as a late-season indicator", reliability: "moderate" },
    { cue: "Presence of the parasitic mold Hypomyces cervinigenus on prior-year fruiting bodies indicates a productive site likely to fruit again", reliability: "anecdotal" }
  ],
  bioactive: { compounds: ["gyromitrin (acetaldehyde N-methyl-N-formylhydrazone)", "N-methyl-N-formylhydrazine (MFH)", "monomethylhydrazine (MMH) - hydrolysis product of gyromitrin", "delta-tocopherol (reported from H. lacunosa s.l. complex)", "lycopene (reported from H. lacunosa s.l. complex)"], medicinalUses: ["Reported pharmacological / antioxidant potential for the H. lacunosa s.l. complex (delta-tocopherol and lycopene content per Leal et al. 2013, Hernandez-Santiago et al. 2016) - not validated clinically and not recommended given toxin profile"], toxinsOfNote: ["gyromitrin", "monomethylhydrazine (MMH) - hepatotoxic, neurotoxic, hemolytic, IARC-classified animal carcinogen; volatile and inhalation-toxic during cooking", "N-methyl-N-formylhydrazine (MFH) - added to California Proposition 65 carcinogen list (effective Dec 2025)"], notes: "MMH inhibits pyridoxal-5-phosphate-dependent enzymes (notably glutamic acid decarboxylase), depleting GABA and producing CNS excitation/seizures; also blocks cytochrome P450 enzymes and depletes glutathione. Toxin content in Helvella is generally lower than in Gyromitra esculenta (which can contain 50-300 mg/kg gyromitrin fresh) but is variable and not zero. Co-listed N-methyl-N-formylhydrazine secondary metabolite is documented from Gyromitra and presumed in Helvella by analogy" },
  dnaBarcode: { itsClade: "Western North American 'H. lacunosa complex' clade - conifer-associated sister lineage to H. dryophila (oak-associated) within the broader H. lacunosa s.l. group; ITS + LSU rDNA sequences define a well-supported monophyletic clade distinct from European H. lacunosa s.s., eastern North American, Asian, and Mexican lineages (H. jocatoi, etc.)", keyPaper: "Nguyen, N.H., Landeros, F., Garibay-Orijel, R., Hansen, K. & Vellinga, E.C. (2013). The Helvella lacunosa species complex in western North America: cryptic species, misapplied names and parasites. Mycologia 105(5): 1275-1286. doi:10.3852/12-391 (PMID 23709487)", notes: "Holotype designated from California collections by Nguyen & Vellinga (2013). At least 11 species are now recognized within the global H. lacunosa s.l. group (Nguyen et al. 2013; Ariyawansa et al. 2015 added H. pseudolacunosa and H. rugosa; Garibay-Orijel et al. 2021 added H. jocatoi from Mexican Abies religiosa forests). H. vespertina is reliably separable from H. dryophila only by ITS sequence or by ecology (conifer vs. oak host)" },
  verification: { sourcesAgreeing: 8, lastVerified: "2026-05-23", consensus: "strong", disputeNotes: "Strong taxonomic consensus since Nguyen et al. (2013). Minor ongoing dispute concerns the exact MMH/gyromitrin concentration in H. vespertina specifically (vs. H. crispa, H. lacunosa s.s., and Gyromitra spp.) - direct quantitative toxin assays for H. vespertina are sparse, so most toxicity guidance is extrapolated from the H. lacunosa complex and Gyromitra literature. Authorities differ on edibility advice: some PNW guides (Arora, Desjardin et al. 'California Mushrooms') list as 'edible when properly cooked'; modern toxicology-oriented sources (Beug/MykoWeb TFWNA, UBC Mushrooms Up!, Trudell & Ammirati) recommend avoiding entirely" }
}
