    { cue: "Overnight lows dropping into 2-7 C range with first frosts at higher elevations", reliability: "strong" },
    { cue: "Fruits 2-4 weeks later than chanterelles in the same forest; often the last major edible of the PNW season", reliability: "moderate" },
    { cue: "Re-fruits on the same log for multiple consecutive autumns (perennial mycelium signal)", reliability: "moderate" },
    { cue: "Peak fruiting tends to follow first significant cold snap after rains begin", reliability: "anecdotal" }
