{
  id: "hericium-erinaceus",
  commonNames: ["Lion's mane", "Pom pom mushroom", "Pom pom blanc", "Bearded tooth", "Bearded hedgehog", "Monkey head", "Yamabushitake", "Old man's beard"],
  scientific: "Hericium erinaceus",
  family: "Hericiaceae",
  order: "Russulales",
  trophicMode: "mixed",
  mycorrhizalPartners: null,
  hostTrees: [
    { common: "Bigleaf maple", scientific: "Acer macrophyllum" },
    { common: "Oregon white oak", scientific: "Quercus garryana" },
    { common: "American beech", scientific: "Fagus grandifolia" },
    { common: "Red oak", scientific: "Quercus rubra" },
    { common: "Black walnut", scientific: "Juglans nigra" },
    { common: "Maple", scientific: "Acer spp." },
    { common: "Birch", scientific: "Betula spp." },
    { common: "Ash", scientific: "Fraxinus spp." }
  ],
  substrate: "Living, wounded, dying, and recently dead hardwood; emerges from branch scars, frost cracks, broken limbs, and lightning wounds on standing trees and from fallen logs. Acts as a weak necrotrophic parasite and saprotroph, causing a white pocket rot in the heartwood. Restricted to deciduous wood; in the PNW most commonly found on bigleaf maple (Acer macrophyllum), distinguishing it from the conifer-associated H. abietis.",
  habitat: "Solitary, single unbranched 'pom pom' fruiting bodies arising from wounds high on the trunks and large branches of living and recently dead hardwood trees, especially bigleaf maple in the PNW; also on fallen hardwood logs. Often perennial at the same site, fruiting in the same wound for several consecutive years. Prefers temperate hardwood and mixed forests with moderate-to-high humidity. Considerably less common in the Pacific Northwest than the conifer-loving H. abietis, but occurs throughout the lowland deciduous forests west of the Cascades, particularly in mixed riparian and oak-maple woodlands.",
  elevationM: { min: 0, max: 1200 },
  regionsPNW: ["Western Washington", "Western Oregon", "Coastal British Columbia", "Puget Sound lowlands", "Willamette Valley", "Columbia River Gorge", "Vancouver Island", "Southwestern Oregon"],
  fruitingMonths: [9, 10, 11, 12, 1, 2],
  peakMonths: [10, 11, 12],
  conditions: {
    minRain7d: 25,
    idealDaysSinceRain: [5, 14],
    tempRangeC: [5, 18],
    humidityMinPct: 80
  },
  identification: {
    cap: "No true cap; the fruiting body is a single rounded, unbranched 'pom pom' or 'bearded' mass of pendant spines, 10-30 cm broad (typically 15-20 cm), all hanging from one short, thick, unbranched tubercle attached directly to the wood; white to cream when fresh, yellowing then browning with age.",
    underside: "The entire visible surface consists of soft, slender, downward-hanging spines (teeth) 1-6 cm long with pointed tips; spines are white when fresh, becoming yellowish to yellowish-brown with age; all spines originate from the same point (single unbranched base), not from multiple branches.",
    stem: "No true stem; attached to the substrate by a very short, broad, sometimes rooted stalk-like tubercle from which all the spines emerge.",
    fleshColor: "White to cream throughout; tough, fibrous, and rubbery; does not stain or change color when cut or bruised.",
    sporePrintColor: "White",
    odor: "Mild, not distinctive when fresh; when cooked the flavor is famously compared to lobster, crab, or scallop.",
    sizeCm: "Whole fruiting body 10-30 cm broad (occasionally to 40 cm); individual spines 1-6 cm long; spores 5-6 x 4-5.5 micrometers, subglobose, smooth to faintly roughened, amyloid."
  },
  edibility: "choice",
  toxicityNotes: "No known toxicity; safe and choice when young and white. Best harvested while the spines are still bright white and firm - older specimens that have yellowed or browned become sour, bitter, and unpleasantly tough. Extensively studied for nootropic effects: contains hericenones and erinacines, compounds that stimulate Nerve Growth Factor (NGF) synthesis and are under active investigation for neuroprotective, cognitive, and nerve-regeneration applications, though clinical efficacy and supplement safety remain unproven.",
  lookalikes: [
    { name: "Bear's head tooth (western)", scientific: "Hericium abietis", catalogId: "hericium-abietis", danger: "edible", keyFeatures: ["branched with spine clusters at tips","on conifer wood"], distinguishingFeature: "Branched, coral-like or cauliflower-like structure with multiple branches each tipped by clusters of spines; grows exclusively on conifer wood (especially Douglas-fir, hemlock, true fir); far more common in the PNW than H. erinaceus." },
    { name: "Coral tooth", scientific: "Hericium coralloides", catalogId: "hericium-coralloides", danger: "edible", keyFeatures: ["open branching form","short spines under 1 cm","on hardwood logs"], distinguishingFeature: "Open, branching coral-like fruiting body with short spines (under 1 cm) lining the undersides of the branches rather than hanging as a single mass; on hardwood logs." },
    { name: "Bear's head tooth (eastern)", scientific: "Hericium americanum", catalogId: "hericium-americanum", danger: "edible", keyFeatures: ["long spines at branch tips","on hardwoods","not single ball form"], distinguishingFeature: "Multiple thick branches with long spines (1-4 cm) clustered at the branch tips; on hardwoods, mainly eastern North America; lacks the single unbranched ball form." },
    { name: "Comb tooth", scientific: "Hericium cirrhatum (Creolophus cirrhatus)", catalogId: "hericium-cirrhatum", danger: "edible", keyFeatures: ["tiered bracket-like caps","short undersurface spines","not a single ball"], distinguishingFeature: "Tiered, bracket-like overlapping caps with short spines on the undersurface; not a single ball; rare in North America." },
    { name: "Hedgehog mushroom", scientific: "Hydnum repandum", catalogId: "hydnum-repandum", danger: "edible", keyFeatures: ["true cap and central stem","downward spines underside","on ground not wood"], distinguishingFeature: "Has a true cap on a true central stem with short downward-pointing spines on the underside; grows on the ground, not on wood." }
  ],
  culinary: {
    flavor: "Sweet, mild, and famously seafood-like when cooked - frequently compared to lobster, crab, or scallop in both flavor and texture; dense, meaty, slightly fibrous chew that holds up to high-heat cooking.",
    preparation: "Tear into bite-sized chunks (don't slice cleanly - the torn surface browns better) and dry-saute in a hot pan first to release internal water, then add butter or oil and brown until golden on all sides; salt at the end. Excellent in 'crab cakes,' creamy pastas, risottos, butter-poached preparations, scallop substitutes, and Asian stir-fries. Always cook thoroughly; never eat raw. Avoid overcrowding the pan, which causes steaming and a soggy texture.",
    preservation: "Dehydrate sliced or torn pieces at 45-55 C until cracker-dry, then store airtight; reconstitute in warm water or stock (reconstituted texture is somewhat spongy). Cooked pieces freeze well for 4-6 months. Also tinctured (dual-extracted in alcohol and hot water) for medicinal preparations targeting the water-soluble polysaccharides and alcohol-soluble erinacines."
  },
  conservationNotes: "Listed on the IUCN Global Fungal Red List and considered uncommon to rare across much of its native range due to its dependence on old, large-diameter hardwood trees with wounds - a habitat reduced by modern forestry. In the Pacific Northwest it is markedly less common than H. abietis. Because the species is easily cultivated commercially, wild foraging for culinary or medicinal use is discouraged; harvest only mature specimens, cut cleanly at the base, and leave the wood substrate undisturbed to allow re-fruiting. Cultivation using non-native strains near wild populations may pose a genetic risk to local mycelia.",
  sources: [
    { name: "MykoWeb - Hericium erinaceus (California Fungi)", url: "https://www.mykoweb.com/CAF/species/Hericium_erinaceus.html" },
    { name: "MushroomExpert.com - Hericium erinaceus by Michael Kuo", url: "https://www.mushroomexpert.com/hericium_erinaceus.html" },
    { name: "First Nature - Hericium erinaceus, Bearded Tooth fungus", url: "https://www.first-nature.com/fungi/hericium-erinaceus.php" },
    { name: "Wikipedia - Hericium erinaceus", url: "https://en.wikipedia.org/wiki/Hericium_erinaceus" },
    { name: "IUCN Global Fungal Red List - Hericium erinaceus", url: "https://redlist.info/iucn/species_view/356812" },
    { name: "PMC - Lion's Mane Mushroom (Hericium erinaceus): A Neuroprotective Fungus (Narrative Review, 2025)", url: "https://pmc.ncbi.nlm.nih.gov/articles/PMC12030463" },
    { name: "Boddy, Crockatt & Ainsworth (2011) - Ecology of Hericium cirrhatum, H. coralloides and H. erinaceus in the UK, Fungal Ecology 4:163-173", url: "https://doi.org/10.1016/j.funeco.2010.10.001" }
  ],
  spores: { lengthMicrons: [5, 7], widthMicrons: [4, 5.5], shape: "Subglobose to short-ellipsoid", ornamentation: "Smooth to finely roughened (sometimes minutely warted under oil immersion)", reaction: "Amyloid (blue-grey in Melzer's reagent); white in mass", notes: "Basidia 25-40 x 5-7 micrometers, four-spored with basal clamps. Hyphal system monomitic and amyloid, hyphae 3-15 micrometers wide with clamp connections and gloeoplerous (oily/resinous) elements that may project into the hymenium as gloeocystidia." },
  microhabitat: { slopeAspect: "Often north- and east-facing slopes and shaded riparian draws where humidity stays high through summer; in the PNW frequently in cool, sheltered creek bottoms and old-growth hardwood pockets", soilPh: [5.0, 7.0], soilTexture: "Indirect - fruits from wood rather than soil; associated with circumneutral, well-drained loams that support mature bigleaf maple, oak, and beech stands", moisturePreference: "High ambient humidity (>80%) with substrate moisture in the wood typically 35-60%; tolerates short summer droughts within sound heartwood but fruits only after sustained autumn rains", indicatorPlants: ["Acer macrophyllum (bigleaf maple)", "Quercus garryana (Oregon white oak)", "Fagus grandifolia (American beech)", "Polystichum munitum (sword fern)", "Oemleria cerasiformis (Indian plum)", "Corylus cornuta (beaked hazel)"], notes: "Tightly tied to large-diameter (>40 cm DBH) living or recently dead hardwoods bearing exposed heartwood wounds 2-10 m above ground; rarely on snags smaller than this. The same wound may re-fruit annually for 5-20 years. In the PNW, occurrence is strongly clustered in lowland oak-maple riparian forests below 600 m and is markedly absent from pure conifer stands." },
  phenologyCues: [
    { cue: "First sustained autumn rains totaling 25+ mm over 7 days following a warm late-summer period", reliability: "strong" },
    { cue: "Nighttime lows dropping into the 5-10 C range while daytime highs remain 12-18 C", reliability: "strong" },
    { cue: "5-14 days after a soaking rain event, with ambient humidity remaining above 80%", reliability: "strong" },
    { cue: "Appearance of young white 'buttons' on previously fruited wounds (perennial re-fruiting from the same scar)", reliability: "strong" },
    { cue: "Co-fruiting with other late-fall hardwood saprotrophs such as Pleurotus ostreatus and Armillaria spp. on bigleaf maple", reliability: "moderate" },
    { cue: "Fruiting following lightning strikes, heavy windstorm limb breakage, or fresh logging wounds opening heartwood", reliability: "moderate" },
    { cue: "Heavier fruiting years following a wet previous spring that recharged deep wood moisture", reliability: "anecdotal" }
  ],
  bioactive: { compounds: ["Hericenones A, B, C, D, E, F, G, H (meroterpenoids from fruiting body)", "Erinacines A, B, C, D, E, F, G, H, I, J, K (cyathane diterpenoids from mycelium)", "Erinacines P, Q, S, Z1-Z5 (additional cyathane diterpenoids from mycelium)", "Hericerins and isohericerinols", "Erinaceolactones A-C", "Isoindoline-1-ones (erinaceolactams)", "Beta-glucan polysaccharides (HEP, HEP-3)", "Heteroxylans and proteoglycans", "Ergosterol and ergosterol peroxide", "Phenolic acids (protocatechuic, gallic, chlorogenic)"], medicinalUses: ["Nerve Growth Factor (NGF) and BDNF synthesis stimulation via JNK/c-Jun signaling (erinacine A and hericenones C-H)", "Investigational neuroprotection in Alzheimer's and Parkinson's preclinical models", "Mild-cognitive-impairment (MCI) cognitive support - Mori et al. (2009) double-blind RCT (3 g/day fruiting body x 16 weeks) showed improvement on HDS-R scale; subsequent trials in MCI and healthy adults (Saitsu 2019, Li 2020, La Monica 2023) report mixed but generally positive cognitive and mood effects", "Adjunct support for peripheral nerve regeneration (preclinical sciatic-nerve crush models)", "Anti-inflammatory effects (lowering IL-6, TNF-alpha; upregulating Nrf2)", "Gastric and duodenal ulcer support in traditional Chinese medicine", "Immunomodulation and putative anti-tumor activity via beta-glucans", "Glycemic and lipid-profile improvement in small clinical trials"], toxinsOfNote: [], notes: "No acute toxicity reported; 13-week oral toxicity study of erinacine-A-enriched mycelium in Sprague-Dawley rats found no observed adverse effect. Rare contact dermatitis and respiratory hypersensitivity have been documented in commercial cultivators. Clinical evidence in humans remains limited to small trials (typically n<50); the 2020 Alzheimer's Drug Discovery Foundation Cognitive Vitality review and 2025 Cambridge narrative review both conclude effects are promising but unproven. Erinacines (from mycelium) cross the blood-brain barrier; hericenones (fruiting body) likely do not, so extract source materially changes pharmacology." },
  dnaBarcode: { itsClade: "Hericium erinaceus sensu stricto clade within Hericiaceae (Russulales); ITS sequences cluster tightly with H. erinaceus s.s. and are sister to the H. coralloides / H. americanum / H. abietis clade. North American populations historically lumped with European H. erinaceus, though some recent multilocus analyses suggest cryptic structure between East Asian, European, and North American lineages.", keyPaper: "Hallenberg, Nilsson & Robledo (2013) - Species complexes in Hericium (Russulales, Agaricomycota) and a new species - Hericium rajchenbergii - from southern South America, Mycological Progress 12:413-420; see also Park et al. (2014) Mycobiology 42:1-10 on ITS phylogeny of Hericium", notes: "GenBank ITS reference sequences for H. erinaceus are abundant (>100 accessions). UNITE species hypothesis SH1545640.08FU. ITS1 and ITS2 both reliably separate H. erinaceus from H. abietis, H. coralloides, and H. americanum; tef1-alpha and rpb2 are used as secondary markers in multilocus studies." },
  verification: { sourcesAgreeing: 7, lastVerified: "2026-05-23", consensus: "strong", disputeNotes: "Strong consensus on morphology, ecology, edibility, and bioactive compound classes. Active scientific debate around (1) clinical efficacy of dietary supplementation for cognition - small trials are mixed and most use proprietary extracts not equivalent to grocery-store fruiting bodies, (2) whether hericenones meaningfully cross the blood-brain barrier in humans, and (3) possible cryptic species structure between Asian, European, and North American H. erinaceus populations." }
}
