    { name: "Pig's Ear", scientific: "Gomphus clavatus", catalogId: "gomphus-clavatus", danger: "edible", keyFeatures: ["lilac ridged underside","tan to ochre-brown cap","grows in arcs/troops"], distinguishingFeature: "Lilac to purplish ridged underside but cap is tan to ochre-brown (not blue-black); grows in arcs/troops rather than fused clusters" },
    { name: "Violet-toothed Polypore", scientific: "Trichaptum abietinum", catalogId: "trichaptum-abietinum", danger: "inedible", keyFeatures: ["purple-edged bracket","on dead conifer wood","tooth-like pore surface"], distinguishingFeature: "Thin tough purple-edged bracket on dead conifer wood (not terrestrial); tooth-like pore surface" },
    { name: "Earth Fan", scientific: "Thelephora terrestris", catalogId: "thelephora-terrestris", danger: "inedible", keyFeatures: ["brown fan-shaped clusters","no blue-purple color","smooth/warted underside"], distinguishingFeature: "Brown to dark-brown fan-shaped clusters; lacks blue-purple coloration; smooth/warted underside, not deeply veined-decurrent" },
    { name: "Bitter Bolete relative / Boletopsis", scientific: "Boletopsis grisea", catalogId: "boletopsis-grisea", danger: "inedible", keyFeatures: ["pored underside","grayish cap","bitter taste"], distinguishingFeature: "Pored (not veined) underside; grayish cap without blue tones; bitter taste" }
