  spores: { lengthMicrons: [6, 7], widthMicrons: [5, 6], shape: "subglobose to broadly ellipsoid", ornamentation: "warty/tuberculate (coarsely warted)", reaction: "Hyaline in KOH; flesh reacts blackish-green with KOH", notes: "Small-spored clade (P. multiplex s.s. and P. atrolazulinus) averages <7 x 6 microns per Voitk et al. 2017; large-spored sister species in the complex exceed 7 x 6 microns. Spore print white." },
  microhabitat: { slopeAspect: "Cool, shaded north- to northeast-facing slopes preferred; also benches and toe-slopes that retain moisture", soilPh: [4.0, 5.5], soilTexture: "Sandy to sandy-loam mineral soil overlain by deep, well-developed conifer duff and feather-moss mat", moisturePreference: "Consistently moist, well-drained sites; duff that stays damp through late summer", indicatorPlants: ["Hylocomium splendens (step moss)", "Pleurozium schreberi (red-stemmed feather moss)", "Vaccinium membranaceum (black huckleberry)", "Vaccinium ovalifolium (oval-leaf blueberry)", "Menziesia ferruginea (false azalea)", "Cornus canadensis (bunchberry)", "Rhytidiopsis robusta (pipecleaner moss)"], notes: "Strongly associated with intact moss/duff mats under mature Picea-Abies-Tsuga canopy; appears sensitive to soil compaction and duff disturbance, and is treated as an old-growth indicator in PNW surveys." },
