{
  id: "suillus-ponderosus",
  commonNames: ["Heavy Suillus", "Ponderous Suillus", "Ponderous Slippery Jack", "Western Yellow Pine Suillus"],
  scientific: "Suillus ponderosus",
  family: "Suillaceae",
  order: "Boletales",
  trophicMode: "mycorrhizal",
  mycorrhizalPartners: ["Pseudotsuga menziesii"],
  hostTrees: [
    { common: "Douglas-fir", scientific: "Pseudotsuga menziesii" }
  ],
  substrate: "duff and mineral soil under Douglas-fir, often in mixed-conifer stands; on the ground, single, scattered, or gregarious",
  habitat: "Ectomycorrhizal partner of Douglas-fir despite the misleading 'Western Yellow Pine' common name (the species does not associate with Pinus ponderosa). Fruits in mixed conifer forest where Douglas-fir is present, frequently alongside its close relative Suillus caerulescens (fat jack) and Suillus lakei (western painted slippery jack). A large, robust, classic PNW autumn bolete of low- to mid-elevation Douglas-fir forest.",
  elevationM: { min: 0, max: 1800 },
  regionsPNW: ["Oregon Coast Range", "Willamette Valley foothills", "Washington Cascades (west slope)", "Puget Sound lowlands", "Olympics", "southern British Columbia (reported)", "Idaho Panhandle"],
  fruitingMonths: [9, 10, 11, 12],
  peakMonths: [10, 11],
  conditions: {
    minRain7d: 20,
    idealDaysSinceRain: [5, 14],
    tempRangeC: [6, 18],
    humidityMinPct: 75
  },
  identification: {
    cap: "Viscid (slimy when wet), glabrous or with veil remnants near the margin only; yellow to cinnamon to reddish brown, sometimes purplish brown, streaked or sometimes tinged green; less innately streaked than Suillus caerulescens; convex becoming broadly convex to nearly flat; 9-29 cm broad - the largest Suillus in the region",
    underside: "Tubes up to 1.5 cm deep, dull yellow, slightly decurrent; pores large (1-3 mm), angular, yellow, staining brownish when bruised",
    stem: "9-14 cm long x 3-6 cm thick, pale yellow, robust and stout; bears a conspicuous heavy gelatinous annulus (ring) that is yellow to tawny-brown and often stained reddish-cinnamon on the underside from the gelatinous outer layer (a key distinguishing trait); lacking glandular dots; interior of base stains greenish when cut",
    fleshColor: "Yellow, unchanging or becoming faintly pinkish; greenish staining in the stem base when cut",
    sporePrintColor: "Cinnamon brown to dull brown",
    odor: "Not distinctive, or sharply acidulous; taste mild, not distinctive",
    sizeCm: "Cap 9-29 cm; stem 9-14 x 3-6 cm; one of the heaviest/largest Suillus species in western North America"
  },
  edibility: "edible",
  toxicityNotes: "Considered edible but of mediocre quality. Like other slippery jacks, the slimy cap cuticle and gelatinous veil should be peeled off before cooking; some people experience GI upset from Suillus species with the slime layer left on. Best when young, firm, and dried before use.",
  lookalikes: [
    { name: "Fat Jack / Douglas-fir Slippery Jack", scientific: "Suillus caerulescens", catalogId: "suillus-caerulescens", danger: "edible", keyFeatures: ["fibrillose-streaked yellow-brown cap","dry membranous veil","Douglas-fir associate"], distinguishingFeature: "Smaller, more innately fibrillose-streaked yellow to tawny-brown cap; partial veil is membranous/fibrillose and remains dry (not heavy and gelatinous); also a Douglas-fir associate and often fruits together with S. ponderosus" },
    { name: "Western Painted Slippery Jack", scientific: "Suillus lakei", catalogId: "suillus-lakei", danger: "edible", keyFeatures: ["dry scaly red-brown cap with fibrillose scales","Douglas-fir associate","no gelatinous ring"], distinguishingFeature: "Dry, scaly, darker red-brown cap with conspicuous reddish fibrillose scales (not viscid); also associated with Douglas-fir; smaller stature and lacks the heavy gelatinous ring" },
    { name: "Slippery Jack", scientific: "Suillus luteus", catalogId: "suillus-luteus", danger: "edible", keyFeatures: ["dark chocolate-brown viscid cap","membranous ring with purplish underside","with 2-needle pines"], distinguishingFeature: "Dark chocolate-brown viscid cap, white-then-yellow membranous (not heavily gelatinous) ring with a purplish underside; associated with 2-needle pines (Pinus) rather than Douglas-fir; introduced in parts of the PNW" },
    { name: "Granulated Slippery Jack", scientific: "Suillus granulatus", catalogId: "suillus-granulatus", danger: "edible", keyFeatures: ["no ring","glandular dots on stem","milky droplets on young pores","with pines"], distinguishingFeature: "Smaller cap, no partial veil/ring at all, conspicuous glandular dots on the stem, droplets ('milking') on young pore surface; associated with pines" },
    { name: "Short-stalked Suillus", scientific: "Suillus brevipes", catalogId: "suillus-brevipes", danger: "edible", keyFeatures: ["no veil/ring","short stem without glandular dots","dark brown viscid cap","with lodgepole/shore pine"], distinguishingFeature: "No veil and no ring, short stem without glandular dots, dark brown viscid cap; associated with lodgepole and shore pine" }
  ],
  culinary: {
    flavor: "Mild, mushroomy but bland; texture is the main issue - soft and slippery when fresh due to the gelatinous cap cuticle and veil",
    preparation: "Peel the slimy cuticle off the cap and remove the gelatinous ring before cooking. Best in dishes that benefit from a soft texture (soups, stews, sauces) or sliced thin and sauteed at high heat to drive off moisture. Young firm buttons are the only worthwhile pickings; older specimens are mushy and waterlogged.",
    preservation: "Drying is the preferred preservation method - slice 5-8 mm thick and dehydrate at 40-50 C until cracker-dry. Dried Suillus rehydrates with improved (less slippery) texture and concentrated flavor, suitable for stocks. Freezing fresh is not recommended due to the slime layer."
  },
  conservationNotes: "Not assessed by IUCN. Locally common in PNW Douglas-fir forest and not considered at risk; depends on intact Douglas-fir mycorrhizal partners, so old-growth removal and clearcuts can locally reduce fruiting. Generally overlooked by commercial harvesters in favor of choicer boletes.",
  sources: [
    { name: "PNW Key Council - Trial Field Key to the Boletes in the Pacific Northwest (Suillus ponderosus entry)", url: "https://www.svims.ca/council/Bolete.htm" },
    { name: "MykoWeb - California Fungi: Suillus caerulescens (with comparison notes to S. ponderosus)", url: "https://www.mykoweb.com/CAF/species/Suillus_caerulescens.html" },
    { name: "Mushrooms Up! (UBC Beaty Museum) - Suillus caerulescens (notes S. ponderosus as a Douglas-fir associate with gelatinous ring)", url: "https://explore.beatymuseum.ubc.ca/mushroomsup/S_caerulescens.html" },
    { name: "MushroomExpert.com - The Genus Suillus (Michael Kuo)", url: "https://www.mushroomexpert.com/suillus.html" },
    { name: "iNaturalist - Suillus ponderosus (Ponderous Slippery Jack) species page", url: "https://www.inaturalist.org/guide_taxa/1478100" },
    { name: "Nguyen, N. H. et al. (2016) - The Suillus spectacle: a phylogenetic study of the genus Suillus. Fungal Biology 120: 1352-1372.", url: "https://doi.org/10.1016/j.funbio.2016.06.008" }
  ],
  spores: { lengthMicrons: [7, 10], widthMicrons: [3, 4.5], shape: "boletoid-fusiform (subfusiform to elongate-elliptical) in profile", ornamentation: "smooth", reaction: "yellowish in KOH; inamyloid", notes: "Basidia 25-30 x 5-8 um, clavate, 4-sterigmate. Cystidia in gelatinized bundles 25-50 x 4-8 um, cylindric to clavate, brown in KOH, often obscured by pigment globules. Pileipellis an ixocutis of 2-4 um wide hyphae. Spore print cinnamon brown in mass." },
  microhabitat: { slopeAspect: "no strong preference; reported on a range of slopes and aspects within Douglas-fir forest, with cooler/moister north- and east-facing slopes often producing more reliable fall flushes in drier interior portions of the range", soilPh: [5.0, 6.5], soilTexture: "moderately well-drained loams, sandy loams, and gravelly forest soils derived from volcanic, glacial, or sedimentary parent material; tolerant of duff-rich forest floor and disturbed roadcut/skid-trail edges", moisturePreference: "mesic; responds to sustained autumn rains after summer drought and continues fruiting into early winter as long as soils stay above freezing and adequately moist", indicatorPlants: ["Pseudotsuga menziesii", "Gaultheria shallon (salal)", "Mahonia nervosa (dull Oregon-grape)", "Polystichum munitum (sword fern)", "Rhododendron macrophyllum", "Vaccinium ovatum (evergreen huckleberry)", "Holodiscus discolor (ocean spray)"], notes: "Strongly tied to the presence of mature or maturing Douglas-fir; does not appear to associate with Pinus ponderosa despite the 'Western Yellow Pine Suillus' common name. Frequent in second-growth Douglas-fir stands, urban park plantings, and Christmas tree farms as well as native forest." },
  phenologyCues: [
    { cue: "Sustained autumn rains (>=2-5 cm cumulative over 7-14 days) following the first cool nights after summer drought", reliability: "strong" },
    { cue: "Soil temperature at 10 cm dropping into the 8-14 C range while daytime air temperatures remain 10-18 C", reliability: "strong" },
    { cue: "Co-fruiting with Suillus caerulescens and Suillus lakei under the same Douglas-fir stands - if those are appearing, S. ponderosus is likely nearby", reliability: "strong" },
    { cue: "Concurrent fruiting of golden chanterelle (Cantharellus formosus) and hedgehog (Hydnum) species in the same Douglas-fir/salal forests", reliability: "moderate" },
    { cue: "Lingering fruiting into early winter (November-December) west of the Cascades during mild, wet winters when soils remain unfrozen", reliability: "moderate" },
    { cue: "Local foragers report flushes ~7-10 days after the first 'real' fall storm system (>=25 mm rain) hits the Coast and Cascade foothills", reliability: "anecdotal" }
  ],
  bioactive: { compounds: ["pulvinic acid-derived bolete pigments (variegatic and related acids, characteristic of Suillus/Boletales)", "ergosterol and related fungal sterols", "beta-glucans (typical of Boletales fruiting bodies)"], medicinalUses: ["no documented traditional or clinical medicinal use; like other Suillus species, beta-glucan content is of general interest for immunomodulatory research but no species-specific studies exist for S. ponderosus"], toxinsOfNote: ["no known specific toxins; gastrointestinal upset has been reported anecdotally from Suillus species when the gelatinous cap cuticle and ring are not removed before cooking, attributed to the slime layer rather than a defined toxin"], notes: "No reports of heavy metal hyperaccumulation specific to S. ponderosus, but as with other ectomycorrhizal boletes, fruiting bodies from roadside or industrially impacted soils should be avoided for consumption." },
  dnaBarcode: { itsClade: "Suillus section Suillus / 'caerulescens-ponderosus' clade within the Douglas-fir-associated lineage of Suillus; ITS sequences of S. ponderosus form a well-supported monophyletic clade sister to S. caerulescens, and S. imitatus var. viridescens has been synonymized into S. ponderosus on ITS evidence (Nguyen et al. 2012)", keyPaper: "Nguyen NH, Kerekes JF, Vellinga EC, Bruns TD (2012). Synonymy of Suillus imitatus, the imitator of two species within the S. caerulescens/ponderosus complex. Mycotaxon 122:389-398. doi:10.5248/122.389. See also Nguyen et al. (2016) Mycologia 108:1216-1228 for global Suillus ITS phylogeny.", notes: "Reference ITS sequences for S. ponderosus are available in GenBank (e.g., representative voucher FC38 from Pseudotsuga menziesii, California). The species is reliably separable from S. caerulescens by ITS despite overlapping morphology; type-specimen ITS data anchor both clades." },
  verification: { sourcesAgreeing: 6, lastVerified: "2026-05-23", consensus: "strong", disputeNotes: "Pre-2012 literature treated Suillus imitatus as a distinct species; Nguyen et al. (2012) showed S. imitatus var. viridescens belongs in the S. ponderosus clade and S. imitatus var. imitatus in the S. caerulescens clade, so older keys and field guides may still list S. imitatus as separate. Spore-size ranges are reported very consistently (7-10 x 3-4.5 um) across Smith & Thiers (1964), Thiers (1975), Kuo (MushroomExpert 2024), and Bessette et al. (2000)." }
}
